 39→func TestToGraphQLItem(t *testing.T) {
 40→	title := "Test Title"
 41→	contentText := "Some content"
 42→	contentURL := "https://example.com"
 43→	sourceURL := "https://referrer.com"
 44→	now := time.Now().UTC().Truncate(time.Millisecond)
 45→
 46→	it := &item.Item{
 47→		ID:           uuid.New(),
 48→		OwnerID:      uuid.New(),
 49→		Type:         "bookmark",
 50→		Status:       "ready",
 51→		Sensitivity:  "normal",
 52→		Title:        &title,
 53→		ContentText:  &contentText,
 54→		ContentURL:   &contentURL,
 55→		Tags:         []string{"go", "test"},
 56→		Metadata:     map[string]any{"key": "val"},
 57→		AutoMetadata: map[string]any{"auto": true},
 58→		Source:       "chrome_extension",
 59→		SourceURL:    &sourceURL,
 60→		CreatedAt:    now,
 61→		UpdatedAt:    now,
 62→		CapturedAt:   now,
 63→	}
 64→
 65→	result := toGraphQLItem(it)
 66→
 67→	if result.ID != it.ID.String() {
 68→		t.Errorf("ID mismatch: %s vs %s", result.ID, it.ID.String())
 69→	}
 70→	if result.Type != model.ItemTypeBookmark {
 71→		t.Errorf("Type = %v, want BOOKMARK", result.Type)
 72→	}
 73→	if result.Status != model.ItemStatusReady {
 74→		t.Errorf("Status = %v, want READY", result.Status)
 75→	}
 76→	if result.Sensitivity != model.SensitivityLevelNormal {
 77→		t.Errorf("Sensitivity = %v, want NORMAL", result.Sensitivity)
 78→	}
 79→	if *result.Title != title {
 80→		t.Errorf("Title = %v, want %v", *result.Title, title)
 81→	}
 82→	if *result.ContentText != contentText {
 83→		t.Errorf("ContentText mismatch")
 84→	}
 85→	if *result.ContentURL != contentURL {
 86→		t.Errorf("ContentURL mismatch")
 87→	}
 88→	if len(result.Tags) != 2 {
 89→		t.Errorf("Tags length = %d, want 2", len(result.Tags))
 90→	}
 91→	if result.Source != "chrome_extension" {
