 93→	}
 94→	if *result.SourceURL != sourceURL {
 95→		t.Errorf("SourceURL mismatch")
 96→	}
 97→	if !result.CreatedAt.Equal(now) {
 98→		t.Errorf("CreatedAt mismatch")
