package cli

import (
	"encoding/json"
	"fmt"
	"os"
	"path/filepath"
)

// Config holds CLI client configuration.
type Config struct {
	APIURL string `json:"api_url"`
	Token  string `json:"token"`
}

const (
	configDirName  = "flotsam"
	configFileName = "config.json"
	defaultAPIURL  = "http://localhost:8081"
)

// ConfigDir returns the configuration directory path, respecting XDG_CONFIG_HOME.
// Creates the directory with 0700 permissions if it does not exist.
func ConfigDir() (string, error) {
	base := os.Getenv("XDG_CONFIG_HOME")
	if base == "" {
		home, err := os.UserHomeDir()
		if err != nil {
			return "", fmt.Errorf("cli: home directory: %w", err)
		}
		base = filepath.Join(home, ".config")
	}
	dir := filepath.Join(base, configDirName)
	if err := os.MkdirAll(dir, 0700); err != nil {
		return "", fmt.Errorf("cli: create config dir: %w", err)
	}
	return dir, nil
}

// configPath returns the full path to the config file.
func configPath() (string, error) {
	dir, err := ConfigDir()
	if err != nil {
		return "", err
	}
	return filepath.Join(dir, configFileName), nil
}

// LoadConfig reads configuration from disk and applies environment variable overrides.
// Returns defaults if the config file does not exist.
func LoadConfig() (*Config, error) {
	cfg := &Config{
		APIURL: defaultAPIURL,
	}

	path, err := configPath()
	if err != nil {
		return nil, err
	}

	data, err := os.ReadFile(path)
	if err != nil {
		if os.IsNotExist(err) {
			applyEnvOverrides(cfg)
			return cfg, nil
		}
		return nil, fmt.Errorf("cli: read config: %w", err)
	}

	if err := json.Unmarshal(data, cfg); err != nil {
		return nil, fmt.Errorf("cli: parse config: %w", err)
	}

	applyEnvOverrides(cfg)
	return cfg, nil
}

// SaveConfig writes configuration to disk with restrictive permissions.
func SaveConfig(cfg *Config) error {
	path, err := configPath()
	if err != nil {
		return err
	}

	data, err := json.MarshalIndent(cfg, "", "  ")
	if err != nil {
		return fmt.Errorf("cli: marshal config: %w", err)
	}

	if err := os.WriteFile(path, data, 0600); err != nil {
		return fmt.Errorf("cli: write config: %w", err)
	}
	return nil
}

// SetURL updates the API URL in the config file.
func SetURL(url string) error {
	cfg, err := LoadConfig()
	if err != nil {
		return err
	}
	cfg.APIURL = url
	return SaveConfig(cfg)
}

// SetToken updates the auth token in the config file.
func SetToken(token string) error {
	cfg, err := LoadConfig()
	if err != nil {
		return err
	}
	cfg.Token = token
	return SaveConfig(cfg)
}

// applyEnvOverrides applies environment variable overrides to the config.
func applyEnvOverrides(cfg *Config) {
	if v := os.Getenv("FLOTSAM_API_URL"); v != "" {
		cfg.APIURL = v
	}
	if v := os.Getenv("FLOTSAM_TOKEN"); v != "" {
		cfg.Token = v
	}
}

