package cli

import (
	"fmt"
	"io"
	"strings"
	"text/tabwriter"
)

// FormatItem writes a single item in a human-readable format.
func FormatItem(w io.Writer, item Item) {
	title := derefOr(item.Title, "(untitled)")
	fmt.Fprintf(w, "ID:          %s\n", item.ID)
	fmt.Fprintf(w, "Type:        %s\n", strings.ToLower(item.Type))
	fmt.Fprintf(w, "Status:      %s\n", strings.ToLower(item.Status))
	fmt.Fprintf(w, "Title:       %s\n", title)
	if item.ContentURL != nil {
		fmt.Fprintf(w, "URL:         %s\n", *item.ContentURL)
	}
	if len(item.Tags) > 0 {
		fmt.Fprintf(w, "Tags:        %s\n", strings.Join(item.Tags, ", "))
	}
	fmt.Fprintf(w, "Sensitivity: %s\n", strings.ToLower(item.Sensitivity))
	fmt.Fprintf(w, "Created:     %s\n", item.CreatedAt)
}

// FormatItemTable writes items as a formatted table.
func FormatItemTable(w io.Writer, items []Item) {
	tw := tabwriter.NewWriter(w, 0, 0, 2, ' ', 0)
	fmt.Fprintln(tw, "ID\tTYPE\tSTATUS\tTITLE\tTAGS\tCREATED")
	for _, item := range items {
		title := Truncate(derefOr(item.Title, "(untitled)"), 40)
		tags := Truncate(strings.Join(item.Tags, ", "), 20)
		created := item.CreatedAt
		if len(created) > 10 {
			created = created[:10]
		}
		fmt.Fprintf(tw, "%s\t%s\t%s\t%s\t%s\t%s\n",
			ShortID(item.ID),
			strings.ToLower(item.Type),
			strings.ToLower(item.Status),
			title,
			tags,
			created,
		)
	}
	tw.Flush()
}

// FormatSearchResult writes a search result with a summary footer.
func FormatSearchResult(w io.Writer, result SearchResult) {
	if len(result.Items) == 0 {
		fmt.Fprintln(w, "No items found.")
		return
	}
	FormatItemTable(w, result.Items)
	more := ""
	if result.HasMore {
		more = " (more available)"
	}
	fmt.Fprintf(w, "\n%d total%s\n", result.Total, more)
}

// Truncate shortens a string to max characters, appending "..." if truncated.
func Truncate(s string, max int) string {
	if max < 4 {
		max = 4
	}
	if len(s) <= max {
		return s
	}
	return s[:max-3] + "..."
}

// ShortID returns the first 8 characters of an ID string.
func ShortID(id string) string {
	if len(id) <= 8 {
		return id
	}
	return id[:8]
}

// derefOr returns the dereferenced string pointer, or the fallback if nil.
func derefOr(s *string, fallback string) string {
	if s == nil {
		return fallback
	}
	return *s
}

