package cli

import (
	"context"
	"encoding/json"
	"net/http"
	"net/http/httptest"
	"testing"
)

// mockGraphQL creates a test server that responds to GraphQL requests.
func mockGraphQL(t *testing.T, handler func(req graphqlRequest) (any, []graphqlError)) *httptest.Server {
	t.Helper()
	return httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		if r.Method != http.MethodPost {
			t.Errorf("expected POST, got %s", r.Method)
		}
		if r.URL.Path != "/graphql" {
			t.Errorf("expected /graphql, got %s", r.URL.Path)
		}
		if ct := r.Header.Get("Content-Type"); ct != "application/json" {
			t.Errorf("expected Content-Type application/json, got %s", ct)
		}

		var gqlReq graphqlRequest
		if err := json.NewDecoder(r.Body).Decode(&gqlReq); err != nil {
			t.Fatalf("decode request: %v", err)
		}

		data, errors := handler(gqlReq)
		dataJSON, _ := json.Marshal(data)

		resp := graphqlResponse{
			Data:   dataJSON,
			Errors: errors,
		}
		w.Header().Set("Content-Type", "application/json")
		json.NewEncoder(w).Encode(resp)
	}))
}

func TestClient_Login(t *testing.T) {
	server := mockGraphQL(t, func(req graphqlRequest) (any, []graphqlError) {
		return map[string]any{
			"login": map[string]any{
				"token": "test-jwt-token",
				"user": map[string]any{
					"id":    "user-123",
					"email": "test@example.com",
				},
			},
		}, nil
	})
	defer server.Close()

	client := NewClient(server.URL, "")
	token, user, err := client.Login(context.Background(), "test@example.com", "password")
	if err != nil {
		t.Fatalf("Login() error = %v", err)
	}
	if token != "test-jwt-token" {
		t.Errorf("token = %q, want %q", token, "test-jwt-token")
	}
	if user.Email != "test@example.com" {
		t.Errorf("email = %q, want %q", user.Email, "test@example.com")
	}
}

func TestClient_AuthHeader(t *testing.T) {
	var gotAuth string
	server := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		gotAuth = r.Header.Get("Authorization")
		resp := graphqlResponse{Data: json.RawMessage(`{"items":{"items":[],"total":0,"hasMore":false}}`)}
		json.NewEncoder(w).Encode(resp)
	}))
	defer server.Close()

	client := NewClient(server.URL, "my-token")
	_, err := client.ListItems(context.Background(), ListOpts{Limit: 10})
	if err != nil {
		t.Fatalf("ListItems() error = %v", err)
	}
	if gotAuth != "Bearer my-token" {
		t.Errorf("Authorization = %q, want %q", gotAuth, "Bearer my-token")
	}
}

func TestClient_NoAuthHeader_WhenEmpty(t *testing.T) {
	var gotAuth string
	server := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		gotAuth = r.Header.Get("Authorization")
		resp := graphqlResponse{Data: json.RawMessage(`{"login":{"token":"t","user":{"id":"1","email":"e"}}}`)}
		json.NewEncoder(w).Encode(resp)
	}))
	defer server.Close()

	client := NewClient(server.URL, "")
	_, _, err := client.Login(context.Background(), "e", "p")
	if err != nil {
		t.Fatal(err)
	}
	if gotAuth != "" {
		t.Errorf("Authorization should be empty for unauthenticated requests, got %q", gotAuth)
	}
}

