	if !strings.Contains(out, "ID") || !strings.Contains(out, "TYPE") || !strings.Contains(out, "TITLE") {
		t.Errorf("missing table header in:\n%s", out)
	}

	// Check data rows
	if !strings.Contains(out, "550e8400") {
		t.Errorf("missing short ID in:\n%s", out)
	}
	if !strings.Contains(out, "text_note") {
		t.Errorf("missing type in:\n%s", out)
	}
	if !strings.Contains(out, "First Note") {
		t.Errorf("missing title in:\n%s", out)
	}
}

func TestFormatSearchResult_Empty(t *testing.T) {
	var buf bytes.Buffer
	FormatSearchResult(&buf, SearchResult{Items: nil, Total: 0})
	if got := strings.TrimSpace(buf.String()); got != "No items found." {
		t.Errorf("got %q, want 'No items found.'", got)
	}
}

func TestFormatSearchResult_WithItems(t *testing.T) {
	result := SearchResult{
		Items: []Item{
			{ID: "abc123def456", Type: "TEXT_NOTE", Status: "READY", Title: strPtr("Test"), CreatedAt: "2025-01-01"},
		},
		Total:   15,
		HasMore: true,
	}

	var buf bytes.Buffer
