package main

import (
	"context"
	"fmt"
	"os"
	"strings"

	ucli "github.com/urfave/cli/v3"
	"golang.org/x/term"

	flt "github.com/ketang/flotsam/api/internal/cli"
	"github.com/ketang/flotsam/api/internal/version"
)

func main() {
	app := &ucli.Command{
		Name:    "flotsam",
		Usage:   "Flotsam CLI — capture, search, and manage your knowledge",
		Version: version.Version,
		Commands: []*ucli.Command{
			loginCmd(),
			configCmd(),
			captureCmd(),
			bookmarkCmd(),
			searchCmd(),
			listCmd(),
			voiceCmd(),
		},
	}

	if err := app.Run(context.Background(), os.Args); err != nil {
		fmt.Fprintf(os.Stderr, "Error: %v\n", err)
		os.Exit(1)
	}
}

func loginCmd() *ucli.Command {
	return &ucli.Command{
		Name:  "login",
		Usage: "Authenticate with the Flotsam API",
		Flags: []ucli.Flag{
			&ucli.StringFlag{Name: "email", Aliases: []string{"e"}, Usage: "email address"},
			&ucli.StringFlag{Name: "password", Aliases: []string{"p"}, Usage: "password (omit for interactive prompt)"},
		},
		Action: func(ctx context.Context, cmd *ucli.Command) error {
			email := cmd.String("email")
			password := cmd.String("password")

			if email == "" {
				fmt.Fprint(os.Stderr, "Email: ")
				if _, err := fmt.Fscanln(os.Stdin, &email); err != nil {
					return fmt.Errorf("cli: read email: %w", err)
				}
			}

			if password == "" {
				fmt.Fprint(os.Stderr, "Password: ")
				passBytes, err := term.ReadPassword(int(os.Stdin.Fd()))
				if err != nil {
					return fmt.Errorf("cli: read password: %w", err)
				}
				fmt.Fprintln(os.Stderr)
				password = string(passBytes)
			}

			cfg, err := flt.LoadConfig()
			if err != nil {
				return err
			}

			client := flt.NewClient(cfg.APIURL, "")
			token, user, err := client.Login(ctx, email, password)
			if err != nil {
				return err
			}

			if err := flt.SetToken(token); err != nil {
				return err
			}

			name := user.Email
			if user.DisplayName != nil {
				name = *user.DisplayName
			}
			fmt.Fprintf(os.Stderr, "Logged in as %s\n", name)
			return nil
		},
	}
}

func configCmd() *ucli.Command {
	return &ucli.Command{
		Name:  "config",
		Usage: "Manage CLI configuration",
		Commands: []*ucli.Command{
			{
				Name:      "set-url",
				Usage:     "Set the API URL",
				ArgsUsage: "<url>",
				Action: func(_ context.Context, cmd *ucli.Command) error {
					url := cmd.Args().First()
					if url == "" {
						return fmt.Errorf("cli: URL argument required")
					}
					if err := flt.SetURL(url); err != nil {
						return err
					}
					fmt.Fprintf(os.Stderr, "API URL set to %s\n", url)
					return nil
				},
			},
			{
				Name:  "show",
				Usage: "Show current configuration",
				Action: func(_ context.Context, _ *ucli.Command) error {
					cfg, err := flt.LoadConfig()
					if err != nil {
						return err
					}
					fmt.Fprintf(os.Stdout, "API URL: %s\n", cfg.APIURL)
					if cfg.Token != "" {
						fmt.Fprintln(os.Stdout, "Token:   (set)")
					} else {
						fmt.Fprintln(os.Stdout, "Token:   (not set)")
					}
					return nil
				},
			},
		},
	}
}

func captureCmd() *ucli.Command {
	return &ucli.Command{
		Name:      "capture",
		Usage:     "Capture a text note",
		ArgsUsage: "<text>",
		Flags: []ucli.Flag{
			&ucli.StringFlag{Name: "title", Aliases: []string{"t"}, Usage: "note title"},
			&ucli.StringSliceFlag{Name: "tags", Usage: "comma-separated tags"},
			&ucli.StringFlag{Name: "sensitivity", Aliases: []string{"s"}, Usage: "sensitivity level (public, normal, sensitive, private)"},
		},
		Action: func(ctx context.Context, cmd *ucli.Command) error {
			content := strings.Join(cmd.Args().Slice(), " ")
			if content == "" {
				return fmt.Errorf("cli: text content required")
			}

			client, err := authedClient()
			if err != nil {
				return err
			}

			input := flt.NoteInput{Content: content}
			if v := cmd.String("title"); v != "" {
				input.Title = &v
			}
			if tags := cmd.StringSlice("tags"); len(tags) > 0 {
				input.Tags = tags
			}
			if v := cmd.String("sensitivity"); v != "" {
				upper := strings.ToUpper(v)
				input.Sensitivity = &upper
			}

			item, err := client.CaptureNote(ctx, input)
			if err != nil {
				return err
			}

			fmt.Fprintf(os.Stderr, "Note captured.\n")
			flt.FormatItem(os.Stdout, *item)
			return nil
		},
	}
}

func bookmarkCmd() *ucli.Command {
	return &ucli.Command{
		Name:      "bookmark",
		Usage:     "Capture a bookmark",
		ArgsUsage: "<url>",
		Flags: []ucli.Flag{
			&ucli.StringFlag{Name: "title", Aliases: []string{"t"}, Usage: "bookmark title"},
			&ucli.StringSliceFlag{Name: "tags", Usage: "comma-separated tags"},
			&ucli.StringFlag{Name: "sensitivity", Aliases: []string{"s"}, Usage: "sensitivity level (public, normal, sensitive, private)"},
		},
		Action: func(ctx context.Context, cmd *ucli.Command) error {
			url := cmd.Args().First()
			if url == "" {
				return fmt.Errorf("cli: URL argument required")
			}

			client, err := authedClient()
			if err != nil {
				return err
			}

			input := flt.BookmarkInput{URL: url}
			if v := cmd.String("title"); v != "" {
				input.Title = &v
			}
			if tags := cmd.StringSlice("tags"); len(tags) > 0 {
				input.Tags = tags
			}
			if v := cmd.String("sensitivity"); v != "" {
				upper := strings.ToUpper(v)
				input.Sensitivity = &upper
			}

			item, err := client.CaptureBookmark(ctx, input)
			if err != nil {
				return err
			}

			fmt.Fprintf(os.Stderr, "Bookmark captured.\n")
			flt.FormatItem(os.Stdout, *item)
			return nil
		},
	}
}

func searchCmd() *ucli.Command {
	return &ucli.Command{
		Name:      "search",
		Usage:     "Search items",
		ArgsUsage: "<query>",
		Flags: []ucli.Flag{
			&ucli.IntFlag{Name: "limit", Aliases: []string{"n"}, Value: 20, Usage: "max results"},
			&ucli.StringSliceFlag{Name: "type", Usage: "filter by item type"},
		},
		Action: func(ctx context.Context, cmd *ucli.Command) error {
			query := strings.Join(cmd.Args().Slice(), " ")
			if query == "" {
				return fmt.Errorf("cli: search query required")
			}

			client, err := authedClient()
			if err != nil {
				return err
			}

			result, err := client.Search(ctx, query, cmd.StringSlice("type"), int(cmd.Int("limit")))
			if err != nil {
				return err
			}

			flt.FormatSearchResult(os.Stdout, *result)
			return nil
		},
	}
}

func listCmd() *ucli.Command {
	return &ucli.Command{
		Name:  "list",
		Usage: "List items",
		Flags: []ucli.Flag{
			&ucli.IntFlag{Name: "limit", Aliases: []string{"n"}, Value: 20, Usage: "max results"},
			&ucli.IntFlag{Name: "offset", Value: 0, Usage: "offset for pagination"},
			&ucli.StringSliceFlag{Name: "type", Usage: "filter by item type"},
			&ucli.StringFlag{Name: "sort", Value: "created_at", Usage: "sort field (created_at, updated_at, title)"},
		},
		Action: func(ctx context.Context, cmd *ucli.Command) error {
			client, err := authedClient()
			if err != nil {
				return err
			}

			opts := flt.ListOpts{
				Types:  cmd.StringSlice("type"),
				Limit:  int(cmd.Int("limit")),
				Offset: int(cmd.Int("offset")),
				Sort:   cmd.String("sort"),
			}

			result, err := client.ListItems(ctx, opts)
			if err != nil {
				return err
			}

			flt.FormatSearchResult(os.Stdout, *result)
			return nil
		},
	}
}

