// authedClient loads config and returns an authenticated client.
func authedClient() (*flt.Client, error) {
	cfg, err := flt.LoadConfig()
	if err != nil {
		return nil, err
	}
	if cfg.Token == "" {
		return nil, fmt.Errorf("cli: not authenticated (run 'flotsam login' first)")
	}
	return flt.NewClient(cfg.APIURL, cfg.Token), nil
}

